#include <bits/stdc++.h>
#define ll long long
using namespace std;
int a[1000][1000];
int main() {
	int n;
	cin>>n;
	int m=0,x,y,xt,yt;
	while (m<n*n) {
		m++;
		if (m==1) {
			x=1;
			y=n/2+1;
		} else if (xt==1&&yt!=n) {
			x=n;
			y=yt+1;
		} else if (xt!=1&&yt==n) {
			x=xt-1;
			y=1;
		} else if (xt==1&&yt==n) {
			x=xt+1;
			y=yt;
		} else if (xt!=1&&yt!=n) {
			if (a[xt-1][yt+1]==0) {
				x=xt-1;
				y=yt+1;
			} else {
				x=xt+1;
				y=yt;
			}
		}
		a[x][y]=m;
		xt=x;
		yt=y;
	}
	for(int i=1; i<=n; i++) {
		for(int j=1; j<=n; j++) {
			cout<<a[i][j]<<" ";
		}
		cout<<"\n";
	}
	return 0;
}
